	`id` int AUTO_INCREMENT NOT NULL,
	`name` varchar(200) NOT NULL,
	`role` varchar(200) NOT NULL,
	`department` varchar(100) NOT NULL,
	`leadershipStyle` varchar(100) NOT NULL,
	`teamSize` int NOT NULL,
	`priorities` text NOT NULL,
